// Authentication Page - Actions and Assertions
// Generated by Qentrix for AG-Helix

import BasePage from './basePage.js';
import { expect } from '@playwright/test';
import * as authPageObjects from '../pageObjects/authPage.js';

class AuthPage extends BasePage {
    constructor(page) {
        super(page);
    }

    // Login Actions
    async navigateToLoginPage() {
        await this.open(process.env.BASE_URL || '');
        return await this.waitForPageLoad();
    }

    async enterUsername(username) {
        await this.waitAndFill(authPageObjects.usernameInput, username);
    }

    async enterPassword(password) {
        await this.waitAndFill(authPageObjects.passwordInput, password);
    }

    async clickLoginButton() {
        await this.waitAndClick(authPageObjects.loginButton);
        await this.waitforNetworkIdle();
    }

    async loginWithCredentials(username, password) {
        await this.enterUsername(username);
        await this.enterPassword(password);
        await this.clickLoginButton();
    }

    async loginWithRole(roleName) {
        const credentials = this.getLoginDataByRole(roleName);
        await this.loginWithCredentials(credentials.username, credentials.password);
    }

    // Registration Actions
    async navigateToRegistrationPage() {
        await this.open((process.env.BASE_URL || '') + '/register');
        return await this.waitForPageLoad();
    }

    async enterRegistrationUsername(username) {
        await this.waitAndFill(authPageObjects.regUsernameInput, username);
    }

    async enterRegistrationEmail(email) {
        await this.waitAndFill(authPageObjects.regEmailInput, email);
    }

    async enterRegistrationPassword(password) {
        await this.waitAndFill(authPageObjects.regPasswordInput, password);
    }

    async enterRegistrationPasswordConfirm(password) {
        await this.waitAndFill(authPageObjects.regPasswordConfirmInput, password);
    }

    async clickRegisterButton() {
        await this.waitAndClick(authPageObjects.registerButton);
        await this.waitforNetworkIdle();
    }

    async registerUser(username, email, password) {
        await this.enterRegistrationUsername(username);
        await this.enterRegistrationEmail(email);
        await this.enterRegistrationPassword(password);
        await this.enterRegistrationPasswordConfirm(password);
        await this.clickRegisterButton();
    }

    // Forgot Password Actions
    async navigateToForgotPasswordPage() {
        await this.open((process.env.BASE_URL || '') + '/forgot-password');
        return await this.waitForPageLoad();
    }

    async enterForgotPasswordEmail(email) {
        await this.waitAndFill(authPageObjects.forgotPasswordEmailInput, email);
    }

    async clickSendResetLinkButton() {
        await this.waitAndClick(authPageObjects.sendResetLinkButton);
        await this.waitforNetworkIdle();
    }

    async submitPasswordResetRequest(email) {
        await this.enterForgotPasswordEmail(email);
        await this.clickSendResetLinkButton();
    }

    // Logout Actions
    async clickUserMenu() {
        await this.waitAndClick(authPageObjects.userMenuButton);
    }

    async clickLogout() {
        await this.waitAndClick(authPageObjects.logoutOption);
        await this.waitforNetworkIdle();
    }

    async logout() {
        await this.clickUserMenu();
        await this.clickLogout();
    }

    // Assertions
    async verifyDashboardLoads() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.dashboardContainer)).toBeVisible();
    }

    async verifyLoginErrorMessage() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.loginErrorMessage)).toBeVisible();
    }

    async verifyValidationError() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.validationError)).toBeVisible();
    }

    async verifyRegistrationErrorMessage(expectedText) {
        await this.wait();
        await this.verifyElementContainsText(authPageObjects.registrationErrorMessage, expectedText);
    }

    async verifyRegistrationSuccess() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.registrationSuccessMessage)).toBeVisible();
    }

    async verifyResetPasswordError() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.resetPasswordErrorMessage)).toBeVisible();
    }

    async verifyResetPasswordSuccess() {
        await this.wait();
        await expect(this.page.locator(authPageObjects.resetPasswordSuccessMessage)).toBeVisible();
    }

    async verifyUserRemainsOnLoginPage() {
        await this.wait();
        const url = await this.getUrl();
        expect(url).toContain('login');
    }

    async verifyRedirectToLoginPage() {
        await this.wait();
        await this.waitForPageLoad();
        const url = await this.getUrl();
        expect(url).toContain('login');
    }
}

export default AuthPage;

